+pub(crate) fn feature_completion_closed(lines: &[String]) -> bool {
+    latest_feature_completion_state(lines).is_some_and(|line| line == FEATURE_MARKED_DONE)
+}
+
+pub(crate) fn is_feature_completion_line(line: &str) -> bool {
+    matches!(
+        line,
+        FEATURE_DONE_PROMPT | FEATURE_MARKED_DONE | FEATURE_REOPENED
+    )
+}
+
+fn latest_feature_completion_state(lines: &[String]) -> Option<&str> {
+    lines
