+#[test]
+fn terminal_app_review_done_prompt_closes_and_reopens_patch_chat() {
+    let root = git_repo("terminal-app-review-done-confirmation");
+    fs::write(root.join("README.md"), "before\n").unwrap();
+    Command::new("git")
+        .current_dir(&root)
+        .args(["add", "README.md"])
+        .status()
+        .unwrap();
+    Command::new("git")
+        .current_dir(&root)
+        .args(["commit", "-m", "ADD initial readme fixture"])
+        .status()
+        .unwrap();
+    let backend = FakeBackend::new([
+        "implemented patch\n@work-leaf patch update readme\n--- a/README.md\n+++ b/README.md\n@@ -1 +1 @@\n-before\n+after\n@work-leaf end\n@work-leaf done",
+        "summary: README changes from before to after",
+        "NO_FINDINGS",
+        "follow-up after reopen\n@work-leaf patch update readme again\n--- a/README.md\n+++ b/README.md\n@@ -1 +1 @@\n-after\n+after second\n@work-leaf end\n@work-leaf done",
+        "summary: README changes from after to after second",
+        "NO_FINDINGS",
+    ]);
+    let chat = CommandChat::new(root, backend.clone()).with_max_review_rounds(4);
+    let mut app = TerminalApp::new(chat, 100, 24);
+
+    app.handle_bytes(b":new update readme\n");
+
+    assert!(app.wait_for_idle(Duration::from_secs(2)));
+    assert_eq!(
+        app.ui().selected_agent().map(AgentId::as_str),
+        Some("user-1")
+    );
+    assert!(
+        app.render_frame()
+            .contains("work-leaf: Is this feature done? yes/no")
+    );
+    assert!(
+        app.ui()
+            .render_left_pane()
+            .contains("\u{1b}[7m>chat-title user-1  working: chat-title  READY\u{1b}[0m")
+    );
+
+    let sends_after_review = backend.sends().len();
+    app.handle_bytes(b"yes\n");
+
+    assert!(
+        app.render_frame()
+            .contains("work-leaf: feature marked done")
+    );
+    assert_eq!(
+        backend.sends().len(),
+        sends_after_review,
+        "answering yes should close the prompt without resuming the agent"
+    );
+    assert!(
+        !app.ui()
+            .render_left_pane()
+            .contains(">chat-title user-1  working: chat-title  READY")
+    );
+
+    app.handle_bytes(b"actually continue\n");
+
+    assert!(app.wait_for_idle(Duration::from_secs(2)));
+    assert!(app.render_frame().contains("work-leaf: feature reopened"));
+    assert!(app.render_frame().contains("follow-up after reopen"));
+    assert!(
+        backend.sends().iter().any(|(target, prompt)| {
+            target.as_str() == "user-1" && prompt == "actually continue"
+        })
+    );
+    assert!(
+        app.render_frame()
+            .contains("work-leaf: Is this feature done? yes/no")
+    );
+
+    app.handle_bytes(b"yes\n");
+
+    assert!(
+        !app.ui()
+            .render_left_pane()
+            .contains(">chat-title user-1  working: chat-title  READY"),
+        "the second clean-review confirmation should close the patch chat highlight"
+    );
+}
